+            Self::IllegalBreak | Self::IllegalContinue => SemanticDiagnosticCategory::ControlFlow,
+            Self::AwaitOutsideAsync | Self::YieldOutsideGenerator => {
+                SemanticDiagnosticCategory::ContextRestriction
+            }
+        }
